public int smallestCommonElement(int[][] mat) {
    HashMap<Integer, Integer> counts = new HashMap<>();
    for (int[] row : mat) {
        for (int num : row) {
            counts.put(num, counts.getOrDefault(num, 0) + 1);
            if (counts.get(num) == mat.length) {
                return num;
            }
        }
    }
    return -1;
}
```

